-- Cross-platform "open a URL in the default browser" in Lua
local function open_url(url)
    local opener
    if package.config:sub(1,1) == "\\" then
        -- Windows
        opener = string.format('start "" "%s"', url)
    elseif os.getenv("HOME") and io.popen("uname"):read("*l") == "Darwin" then
        -- macOS
        opener = string.format('open "%s"', url)
    else
        -- Linux / BSD
        opener = string.format('xdg-open "%s"', url)
    end
    os.execute(opener)
end

